example.code:
#[cfg(test)]
mod tests {
    use super::*;
    use mockall::predicate::*;
    use mockall::mock;

    mock! {
        Database {}
        impl Database {
            async fn fetch_user_by_id(&self, id: i32) -> Result<Option<User>, sqlx::Error>;
        }
    }

    #[tokio::test]
    async fn test_get_by_id_returns_user() {
        let mut mock_db = MockDatabase::new();
        mock_db
            .expect_fetch_user_by_id()
            .with(eq(1))
            .times(1)
            .returning(|_| Ok(Some(create_test_user())));
        let service = UserService::new(&mock_db);
        let result = service.get_by_id(1).await;
        assert!(result.is_ok());
    }

    #[tokio::test]
    async fn test_get_by_id_not_found() {
        let mut mock_db = MockDatabase::new();
        mock_db
            .expect_fetch_user_by_id()
            .with(eq(999))
            .returning(|_| Ok(None));
        let service = UserService::new(&mock_db);
        let result = service.get_by_id(999).await;
        assert!(matches!(result, Err(AppError::NotFound(_))));
    }
}

#[tokio::test]
async fn test_create_user() {
    let app = setup_app().await; // creates test DB, runs migrations, returns Router
    let response = app
        .oneshot(
            Request::builder()
                .method("POST")
                .uri("/api/v1/users")
                .header("Content-Type", "application/json")
                .body(Body::from(
                    json!({"name":"John","email":"john@example.com","password":"pass1234"})
                        .to_string(),
                ))
                .unwrap(),
        )
        .await
        .unwrap();
    assert_eq!(response.status(), StatusCode::CREATED);
}
